import Colors from '@dynatrace/strato-design-tokens/colors';

import type { FilterFieldError } from '../../types/filter-field-error.js';
import type {
  FilterFieldGroupNode,
  FilterFieldNode,
  FilterFieldSearchOperatorNode,
} from '../../types/tree-nodes.js';
import {
  isFilterFieldStatementNode,
  isLogicalOperator,
} from '../tree-node-guards.js';
import { convertToErrorNode } from './lezer-tree-conversion/node-mutations.js';
import type { FilterFieldProps } from '../../FilterField.types.js';
import type {
  FilterFieldFlatGroupNode,
  FilterFieldFlatNode,
  FilterFieldLogicalOperatorNode,
} from '../../types/conversion-utils.js';

/**
 * Iterate over the parsed document and convert the lezer tree to an object.
 * @internal
 */
export function sortFilterFieldTree(
  tree: FilterFieldFlatGroupNode | undefined,
  parserConfig: FilterFieldProps['parserConfig'],
  doc?: string,
): {
  tree: FilterFieldGroupNode | undefined;
  errors: FilterFieldError[];
  isValidSearch: boolean;
} {
  if (!tree) {
    return { tree, errors: [], isValidSearch: true };
  }

  const { tree: _cleanedTree, searchOperators } = groupByLogicalOperators({
    tree,
  });
  let errors: FilterFieldError[] = [];

  let cleanedTree = _cleanedTree;
  let isValidSearch;
  // eslint-disable-next-line @typescript-eslint/no-deprecated
  if (parserConfig?.searchConversion === true) {
    ({
      tree: cleanedTree,
      errors,
      isValidSearch,
    } = checkValidSearchOperators(cleanedTree, searchOperators, doc));
  }

  return {
    tree: cleanedTree,
    errors,
    isValidSearch: isValidSearch ?? false,
  };
}

type LogicalOperator = FilterFieldGroupNode['logicalOperator'];

/**
 * Function to group the filter statements depending on the logical operators used.
 */
function groupByLogicalOperators(
  data: {
    tree: FilterFieldFlatGroupNode;
    searchOperators?: FilterFieldSearchOperatorNode[];
  },
  group?: FilterFieldGroupNode,
): {
  tree: FilterFieldGroupNode;
  searchOperators: FilterFieldSearchOperatorNode[];
} {
  const { tree, searchOperators = [] } = data;
  const sortedTree: FilterFieldGroupNode = group ?? {
    type: 'Group',
    range: tree.range,
    logicalOperator: 'AND',
    explicit: tree.explicit,
    explicitLogicalOperator: false,
    children: [],
  };

  let prevLogicalOperator: LogicalOperator | null | undefined;
  let currentLogicalOperator: LogicalOperator | undefined | null;
  let nestedTree: FilterFieldGroupNode | undefined;

  // In case of an empty group, return an empty group.
  if (
    tree.type === 'Group' &&
    (tree.children.length === 0 || tree.children[0].type === 'Error')
  ) {
    return {
      tree: {
        ...tree,
        logicalOperator: 'AND',
        explicitLogicalOperator: false,
        children: tree.children as FilterFieldNode[],
      },
      searchOperators,
    };
  }

  for (const [index, child] of tree.children.entries()) {
    // push error nodes to the tree, except logical operators
    // as they need to be handled separately
    if (child.type === 'Error' && !isLogicalOperator(child)) {
      sortedTree.children.push(child);
    }

    if (
      child.type === 'Statement' ||
      (child.type === 'Group' && child.explicit)
    ) {
      const prevNode: FilterFieldFlatNode | undefined =
        tree.children[index - 1];

      if (
        child.type === 'Statement' &&
        child.comparisonOperator?.type === 'SearchOperator'
      ) {
        // Store search operator to potentially mark all of them as errors in a later step.
        searchOperators.push(child.comparisonOperator);
      }

      prevLogicalOperator = currentLogicalOperator;
      currentLogicalOperator = (
        isLogicalOperator(prevNode)
          ? // DEPRECATION: [APPDEV-13773] BREAKING-CHANGE: Exclude logical operator node from public tree type.
            // Check how to best deal with the logical operator conversion here.

            (prevNode as FilterFieldLogicalOperatorNode).value.toUpperCase()
          : null
      ) as FilterFieldGroupNode['logicalOperator'];

      if (prevNode === undefined) {
        currentLogicalOperator = undefined;
      }

      // In case the previous logical operator is not equal to the current, we need to group the
      // previous statement and the current statement and nest them in the tree.
      // An undefined logical operator indicates that there are no previous statements yet.
      // E.g.:
      /*
        a = 1 OR b = 2 c = 2
        tree before implicit and: { or: ['a = 1', 'b = 2' ]}
        -> pop the last statement of the current tree and add it to a new nested
           tree with the current statement
        tree after implicit and:  { or: ['a = 1', { and: ['b = 2', 'c = 2]} ]}
       */
      const shouldCreateNestedTree =
        prevLogicalOperator !== undefined &&
        currentLogicalOperator !== undefined &&
        currentLogicalOperator !== prevLogicalOperator &&
        // For an explicit logical operator, a nested tree has already been created when handling the logical operator.
        prevNode?.type !== 'LogicalOperator';

      if (shouldCreateNestedTree) {
        // Pop last node of previous tree.
        const prevNode = sortedTree.children.pop();
        if (!prevNode) {
          continue;
        }

        let nestedChildren: FilterFieldNode;
        if (child.type === 'Group') {
          ({ tree: nestedChildren } = groupByLogicalOperators({
            tree: child,
            searchOperators,
          }));
        } else {
          nestedChildren = child;
        }

        // Create new nested tree to push to the previous group.
        const groupedChildren: FilterFieldNode[] = [prevNode, nestedChildren];

        nestedTree = {
          type: 'Group',
          range: {
            from: prevNode.range.from,
            to: groupedChildren[groupedChildren.length - 1]?.range.to,
          },
          children: groupedChildren,
          logicalOperator: currentLogicalOperator ?? 'AND',
          explicitLogicalOperator:
            currentLogicalOperator !== null &&
            currentLogicalOperator !== undefined,
          explicit: false,
        };

        sortedTree.children.push(nestedTree);

        // Update the nested tree's range to include all of the new group if need be.
        if (sortedTree.range.to < nestedTree.range.to) {
          sortedTree.range.to = nestedTree.range.to;
        }
      } else {
        let nestedChildren: FilterFieldNode;
        if (child.type === 'Group') {
          ({ tree: nestedChildren } = groupByLogicalOperators(
            { tree: child, searchOperators },
            // Pass the created nested tree for implicit groups only to avoid circular structures.
            // The sorted tree returned at the end of the function is set to the 'group' parameter = nestedTree.
            // If the child is an explicit group and we would pass the nestedTree, it would be pushed into the
            // sortedTree of the previous recursion again when returning the current sortedTree.
            child.explicit ? undefined : nestedTree,
          ));
        } else {
          nestedChildren = child;
        }

        // If the current node is a group, recursively add the group to the tree.
        (nestedTree ?? sortedTree).children.push(nestedChildren);

        if (nestedTree) {
          nestedTree.range.to = child.range.to;
        }
        if (!sortedTree.explicit && sortedTree.range.to < child.range.to) {
          sortedTree.range.to = child.range.to;
        }
      }
    }

    // If the child is an explicit logical operator, depending on the previous
    // logical operator, we either just push it to the current tree, or create
    // a nested tree to group the relevant statements and logical operators.
    // E.g.:
    /*
      a = 1 b = 1 OR c = 2
      Once at the explicit 'OR', group the previous statements (a, b).

      a = 1 OR b = 2 c = 2
      Once at the implicit 'AND', group the previous statement
      and the current statement (b, c).
     */
    if (isLogicalOperator(child)) {
      // DEPRECATION: [APPDEV-13773] BREAKING-CHANGE: Exclude logical operator node from public tree type.
      // Check how to best deal with the logical operator conversion here.

      const convertedChild: FilterFieldLogicalOperatorNode =
        child as FilterFieldLogicalOperatorNode;

      prevLogicalOperator = currentLogicalOperator;
      currentLogicalOperator =
        convertedChild.value.toUpperCase() as FilterFieldGroupNode['logicalOperator'];

      if (
        prevLogicalOperator !== undefined &&
        prevLogicalOperator !== currentLogicalOperator
      ) {
        if (
          !nestedTree ||
          (currentLogicalOperator === 'OR' &&
            currentLogicalOperator !== sortedTree.logicalOperator &&
            // Either of the trees has an explicit logical operator. The current logical operator does not match
            // the operator of the sorted tree. We need to move the existing sorted tree to a nested tree.
            (sortedTree.explicitLogicalOperator ||
              nestedTree.explicitLogicalOperator ||
              // Some deeper nested mixture of implicit and explicit logical and.
              // With a current logical OR operator, we need to move the existing sorted tree to a nested tree.
              sortedTree.logicalOperator === nestedTree.logicalOperator)) ||
          // The current logical operator is an explicit AND with a previous implicit AND and logical OR.
          // E.g.: b=2 OR c=3 d=4 AND e=5
          // In this case, we already have a nested tree, but still have to create a new one to group
          // The implicit and explicit logical AND while not losing the logical OR.
          (sortedTree.logicalOperator === 'OR' &&
            currentLogicalOperator === 'AND')
        ) {
          // Create a new nested tree.
          nestedTree = {
            type: 'Group',
            logicalOperator: 'AND',
            range: { from: -1, to: -1 },
            explicit: false,
            explicitLogicalOperator:
              currentLogicalOperator === 'AND' ||
              (currentLogicalOperator === 'OR' &&
                sortedTree.explicitLogicalOperator),
            children: [],
          };

          // Add all the previous nodes to the new tree until we get to an explicit
          // logical operator 'OR' operator.
          // E.g.:
          /*
            a = 1 AND b = 1 c = 1 OR d = 2 e = 2
            Once at the logical 'OR', create a new nested tree to group all the previous statements
            that are connected with 'AND'.
            All of them need to be removed from the current tree and pushed to the nested tree.

            a = 1 OR b = 2 AND c = 2
            Once at the logical 'AND', create a new nested tree, but only include the previous statement (b)
            and don't move anything before.

            a = 1 b = 2 AND c = 2
            Once at the logical 'AND', create a new nested tree, but only include the previous statement (b)
            and don't move anything before to be able to distinguish between explicit and implicit logical and.
           */
          let abortGrouping = false;
          do {
            const previousNode = sortedTree.children.pop();
            // Nothing left in the tree -> break;
            if (!previousNode) {
              break;
            }

            nestedTree.children.push(previousNode);

            // If the previous node is a logical 'OR' operator or the sorted tree does not have an explicit logical operator, but
            // the current logical operator is an explicit 'AND', stop pushing nodes to the nested tree.
            if (
              // Switching from logical and to logical or.
              (sortedTree.explicitLogicalOperator &&
                sortedTree.logicalOperator === 'OR') ||
              // Mixture of implicit and explicit logical and.
              (!sortedTree.explicitLogicalOperator &&
                currentLogicalOperator === 'AND')
            ) {
              abortGrouping = true;
            }
          } while (!abortGrouping);

          // Reverse the nested tree to restore the original order of the nodes.
          nestedTree.children.reverse();

          // Set the start and end index of the nested tree.
          nestedTree.range.from = nestedTree.children[0]?.range.from;
          nestedTree.range.to =
            nestedTree.children[nestedTree.children.length - 1]?.range.to;

          if (
            currentLogicalOperator === 'AND' &&
            nestedTree.range.to < child.range.to
          ) {
            nestedTree.range.to = child.range.to;
          }

          if (!nestedTree.children[0]) {
            nestedTree = undefined;
          } else {
            // Push the nested tree to the current tree.
            sortedTree.children.push(nestedTree);
            if (currentLogicalOperator === 'OR') {
              sortedTree.logicalOperator = currentLogicalOperator;
            }
          }
        }

        if (
          currentLogicalOperator === 'OR' ||
          (nestedTree?.explicitLogicalOperator === false &&
            currentLogicalOperator === 'AND')
        ) {
          nestedTree = undefined;
        }
      } else {
        (nestedTree ?? sortedTree).explicitLogicalOperator =
          child.type !== 'Error';
      }

      // Add the logical operator node to the tree if it is an error node
      if (child.type === 'Error') {
        (nestedTree ?? sortedTree).children.push(child);
      }

      if (!nestedTree) {
        if (!prevLogicalOperator) {
          sortedTree.logicalOperator = currentLogicalOperator;
        }

        if (currentLogicalOperator && child.type !== 'Error') {
          sortedTree.explicitLogicalOperator = true;
        }
        if (sortedTree.range.to < child.range.to) {
          sortedTree.range.to = child.range.to;
        }
      }
    }

    if (
      child.type === 'Error' &&
      (child.value === 'OR' || child.value === 'AND')
    ) {
      (nestedTree ?? sortedTree).explicitLogicalOperator = false;
    }
  }

  return { tree: sortedTree, searchOperators };
}

/**
 * Function to check whether search operators are only used in a valid context.
 * A combination of logical or with statements other than search statements is not allowed.
 * Due to the higher precedence of logical and, it is sufficient to check only the root level of the tree
 * and only if the root node's logical operator is a logical or.
 */
function checkValidSearchOperators(
  root: FilterFieldGroupNode,
  searchOperators?: FilterFieldSearchOperatorNode[],
  doc?: string,
): {
  tree: FilterFieldGroupNode;
  errors: FilterFieldError[];
  isValidSearch: boolean;
} {
  const errors: FilterFieldError[] = [];
  const hasStatementsOtherThanSearch = hasNonSearchStatements(root);
  const isSearchInNestedGroup = isSearchOperatorInsideGroup(root, true);

  // Check if the document ends with 'OR ' to catch incomplete logical operators at the end of the input.
  const endsWithOR = typeof doc === 'string' && doc.endsWith('OR ');
  const hasOr = root.logicalOperator === 'OR' || endsWithOR;

  if (
    // For a group with an explicit or, we need at least two children that are not logical operators
    // for it to invalidate search operators.
    // E.g.:
    // ›foo = bar or‹ should still show the search suggestion, since the user may want to search for "or".
    // At this point, the "or" is already detected as logical operator (converted to an error node).
    searchOperators &&
    ((root.children.filter((child) => !isLogicalOperator(child)).length > 1 &&
      hasStatementsOtherThanSearch &&
      hasOr &&
      searchOperators) ||
      isSearchInNestedGroup)
  ) {
    for (const node of searchOperators) {
      convertToErrorNode(node);
      errors.push({
        range: node.range,
        message: {
          type: 'unsupportedSearchWithLogicalOr',
          details: `<span style="color: ${Colors.Syntax.Operators}">AND</span>`,
        },
      });
    }
  }

  const isValidSearch =
    errors.length === 0 &&
    !(hasOr && hasStatementsOtherThanSearch) &&
    !isSearchInNestedGroup;

  return { tree: root, errors, isValidSearch };
}

/** Check if any statements other than search statements are used in a tree. */
function hasNonSearchStatements(root: FilterFieldGroupNode): boolean {
  return root.children.some((node) => {
    if (node.type === 'Group') {
      return hasNonSearchStatements(node);
    }

    return (
      isFilterFieldStatementNode(node) &&
      node.comparisonOperator !== undefined &&
      node.comparisonOperator.type !== 'SearchOperator'
    );
  });
}

/**
 * Recursively checks if a search operator or a related error node
 * exists inside any non-root group in the filter tree.
 */
function isSearchOperatorInsideGroup(
  node: FilterFieldGroupNode,
  isRoot: boolean = true,
): boolean {
  for (const child of node.children) {
    // Recursively check nested groups
    if (child.type === 'Group') {
      if (isSearchOperatorInsideGroup(child, false)) {
        return true;
      }
    }
    // Check for search operator or error in non-root groups
    if (
      !isRoot &&
      isFilterFieldStatementNode(child) &&
      child.comparisonOperator?.type === 'Error' &&
      (child.comparisonOperator.value === '* ~' ||
        child.comparisonOperator.value === '*~')
    ) {
      return true;
    }
  }
  return false;
}
